#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>

int main() {
    pid_t pid;
    printf("Before fork: Process ID = %d\n", getpid());

    pid = fork();

    if (pid < 0) {
        printf("Fork failed!\n");
        return 1;
    }
    else if (pid == 0) {
        // Child process
        printf("Child: My PID = %d, Parent PID = %d\n", 
               getpid(), getppid());
    }
    else {
        // Parent process
        printf("Parent: My PID = %d, Child PID = %d\n", 
               getpid(), pid);
        wait(NULL); // Wait for child to complete
    }

    return 0;
}

#include <stdio.h>
#include <pthread.h>
#include <semaphore.h>

sem_t mutex;  // Semaphore for mutual exclusion
int shared_variable = 0;

void* thread_function(void* arg) {
    int local = *(int*)arg;

    // Wait (decrement) on semaphore
    sem_wait(&mutex);

    // Critical Section - only one thread here at a time
    shared_variable++;
    printf("Thread %d: shared_variable = %d\n", local, shared_variable);

    // Signal (increment) on semaphore
    sem_post(&mutex);

    return NULL;
}

int main() {
    pthread_t threads[5];
    int ids[5];

    // Initialize semaphore: 1 = binary (mutex)
    sem_init(&mutex, 0, 1);

    // Create 5 threads
    for (int i = 0; i < 5; i++) {
        ids[i] = i;
        pthread_create(&threads[i], NULL, thread_function, &ids[i]);
    }

    // Join all threads
    for (int i = 0; i < 5; i++) {
        pthread_join(threads[i], NULL);
    }

    printf("Final value: %d\n", shared_variable);
    sem_destroy(&mutex);

    return 0;
}
